+/**
+ * Simple synchronous HTTP client using Sock class.
+ */
+class HTTPClient
+{
+public:
+    HTTPClient(const std::string& host, uint16_t port, std::chrono::seconds timeout)
+        : m_host(host), m_port(port), m_timeout(timeout) {}
+
+    HTTPReply Post(const std::string& endpoint,
+                   const std::vector<std::pair<std::string, std::string>>& headers,
+                   const std::string& body);
+
+private:
+    std::string m_host;
+    uint16_t m_port;
+    std::chrono::seconds m_timeout;
+
+    std::unique_ptr<Sock> Connect();
+    bool SendRequest(Sock& sock, const std::string& request);
+    HTTPReply ReadResponse(Sock& sock);
+    bool WaitForReadable(Sock& sock, std::chrono::milliseconds timeout);
+};
+
+std::unique_ptr<Sock> HTTPClient::Connect()
+{
+    std::vector<CService> services = Lookup(m_host, m_port, /*fAllowLookup=*/true, /*nMaxSolutions=*/256);
+    if (services.empty()) {
+        throw CConnectionFailed(strprintf("Could not resolve host: %s", m_host));
+    }
+
+    for (const CService& service : services) {
+        auto sock = ConnectDirectly(service, /*manual_connection=*/true);
+        if (sock) return sock;
+    }
+
+    throw CConnectionFailed(strprintf("Could not connect to the server %s:%d", m_host, m_port));
+}
+
+bool HTTPClient::SendRequest(Sock& sock, const std::string& request)
+{
+    size_t total_sent = 0;
+    const char* data = request.data();
+    size_t remaining = request.size();
+    auto deadline = std::chrono::steady_clock::now() + m_timeout;
+
+    while (remaining > 0) {
+        if (std::chrono::steady_clock::now() >= deadline) {
+            return false;
+        }
+
+        // Wait for socket to be writable
+        Sock::Event event{0};
+        auto time_left = std::chrono::duration_cast<std::chrono::milliseconds>(
+            deadline - std::chrono::steady_clock::now());
+        if (time_left.count() <= 0 || !sock.Wait(time_left, Sock::SEND, &event)) {
+            return false;
+        }
+
+        if (!(event & Sock::SEND)) {
+            continue;
+        }
+
+        ssize_t sent = sock.Send(data + total_sent, remaining, MSG_NOSIGNAL);
+        if (sent < 0) {
+            int err = WSAGetLastError();
+            if (err == WSAEWOULDBLOCK || err == WSAEINTR) {
+                continue;
+            }
+            return false;
+        }
+        total_sent += sent;
+        remaining -= sent;
+    }
+    return true;
+}
+
+bool HTTPClient::WaitForReadable(Sock& sock, std::chrono::milliseconds timeout)
+{
+    Sock::Event event{0};
+    if (!sock.Wait(timeout, Sock::RECV, &event)) {
+        return false;
+    }
+    return (event & Sock::RECV) != 0;
+}
+
+HTTPReply HTTPClient::ReadResponse(Sock& sock)
+{
+    HTTPReply reply;
+    std::vector<std::byte> buffer;
+    auto deadline = std::chrono::steady_clock::now() + m_timeout;
+
+    // Read data until we have complete headers
+    bool headers_complete = false;
+    size_t headers_end = 0;
+
+    while (!headers_complete) {
+        if (std::chrono::steady_clock::now() >= deadline) {
+            reply.error = HTTP_TIMEOUT;
+            return reply;
+        }
+
+        auto time_left = std::chrono::duration_cast<std::chrono::milliseconds>(
+            deadline - std::chrono::steady_clock::now());
+        if (time_left.count() <= 0) {
+            reply.error = HTTP_TIMEOUT;
+            return reply;
+        }
+
+        if (!WaitForReadable(sock, time_left)) {
+            reply.error = HTTP_TIMEOUT;
+            return reply;
+        }
+
+        std::byte recv_buf[4096];
+        ssize_t nrecv = sock.Recv(recv_buf, sizeof(recv_buf), /*flags=*/0);
+
+        if (nrecv < 0) {
+            int err = WSAGetLastError();
+            if (err == WSAEWOULDBLOCK || err == WSAEINTR) {
+                continue;
+            }
+            reply.error = HTTP_READ_ERROR;
+            return reply;
+        }
+
+        if (nrecv == 0) {
+            // Connection closed before headers complete
+            reply.error = HTTP_EOF;
+            return reply;
+        }
+
+        buffer.insert(buffer.end(), recv_buf, recv_buf + nrecv);
+
+        // Check for header terminator
+        std::string_view buf_view(reinterpret_cast<const char*>(buffer.data()), buffer.size());
+        size_t pos = buf_view.find("\r\n\r\n");
+        if (pos != std::string::npos) {
+            headers_complete = true;
+            headers_end = pos + 4;
+        }
+
+        // Sanity check on header size
+        if (buffer.size() > bitcoin_http::MAX_HEADERS_SIZE && !headers_complete) {
+            throw std::runtime_error("HTTP response headers too large");
+        }
+    }
+
+    // Parse http status
+    util::LineReader reader(std::span<const std::byte>(buffer.data(), headers_end), bitcoin_http::MAX_HEADERS_SIZE);
+    auto status_line = reader.ReadLine();
+    if (!status_line) {
+        throw std::runtime_error("Failed to read HTTP status line");
+    }
+
+    const std::string& status_str = *status_line;
+    if (status_str.size() < 12 || !status_str.starts_with("HTTP/")) {
+        throw std::runtime_error("Invalid HTTP status line");
+    }
+
+    size_t space1 = status_str.find(' ');
+    if (space1 == std::string::npos || space1 + 4 > status_str.size()) {
+        throw std::runtime_error("Invalid HTTP status line format");
+    }
+
+    std::string status_code_str = status_str.substr(space1 + 1, 3);
+    auto status_code = ToIntegral<int>(status_code_str);
+    if (!status_code) {
+        throw std::runtime_error("Invalid HTTP status code");
+    }
+    reply.status = *status_code;
+
+    auto headers = bitcoin_http::Read(reader);
+
+    // Determine body length
+    size_t content_length = 0;
+    bool chunked = false;
+
+    auto transfer_encoding = bitcoin_http::FindFirst(headers, "transfer-encoding");
+    if (transfer_encoding && ToLower(*transfer_encoding).find("chunked") != std::string::npos) {
+        chunked = true;
+    } else {
+        auto content_length_header = bitcoin_http::FindFirst(headers, "content-length");
+        if (content_length_header) {
+            auto len = ToIntegral<size_t>(*content_length_header);
+            if (!len) {
+                throw std::runtime_error("Invalid Content-Length");
+            }
+            content_length = *len;
+        }
+    }
+
+    // Check for reasonable body size
+    if (content_length > MAX_BODY_SIZE) {
+        throw std::runtime_error("HTTP response body too large");
+    }
+
+    // Extract any body data already received
+    std::vector<std::byte> body_buffer;
+    if (buffer.size() > headers_end) {
+        body_buffer.insert(body_buffer.end(),
+                          buffer.begin() + headers_end,
+                          buffer.end());
+    }
+
+    // Read remaining body
+    if (chunked) {
+        // Handle chunked transfer encoding
+        std::string body;
+        std::vector<std::byte> chunk_buffer = body_buffer;
+
+        while (true) {
+            if (std::chrono::steady_clock::now() >= deadline) {
+                reply.error = HTTP_TIMEOUT;
+                return reply;
+            }
+
+            // Try to parse a chunk from current buffer
+            std::string chunk_data(reinterpret_cast<const char*>(chunk_buffer.data()), chunk_buffer.size());
+            size_t line_end = chunk_data.find("\r\n");
+
+            if (line_end != std::string::npos) {
+                // Parse chunk size
+                std::string size_str = chunk_data.substr(0, line_end);
+                // Ignore chunk extensions
+                size_t semi = size_str.find(';');
+                if (semi != std::string::npos) {
+                    size_str = size_str.substr(0, semi);
+                }
+
+                size_t chunk_size{0};
+                auto [p, ec] = std::from_chars(size_str.data(), size_str.data() + size_str.size(), chunk_size, /*base=*/16);
+                if (ec != std::errc{} || p != size_str.data() + size_str.size()) {
+                    throw std::runtime_error("Invalid chunk size");
+                }
+
+                if (chunk_size == 0) {
+                    // Last chunk
+                    break;
+                }
+
+                // Check if we have the full chunk
+                size_t chunk_start = line_end + 2;
+                size_t chunk_end = chunk_start + chunk_size + 2; // +2 for trailing CRLF
+
+                if (chunk_buffer.size() >= chunk_end) {
+                    // Extract chunk data
+                    body.append(reinterpret_cast<const char*>(chunk_buffer.data() + chunk_start), chunk_size);
+
+                    // Remove processed data
+                    chunk_buffer.erase(chunk_buffer.begin(), chunk_buffer.begin() + chunk_end);
+                    continue;
+                }
+            }
+
+            // Need more data
+            auto time_left = std::chrono::duration_cast<std::chrono::milliseconds>(
+                deadline - std::chrono::steady_clock::now());
+            if (time_left.count() <= 0 || !WaitForReadable(sock, time_left)) {
+                reply.error = HTTP_TIMEOUT;
+                return reply;
+            }
+
+            std::byte recv_buf[4096];
+            ssize_t nrecv = sock.Recv(recv_buf, sizeof(recv_buf), /*flags=*/0);
+
+            if (nrecv < 0) {
+                int err = WSAGetLastError();
+                if (err == WSAEWOULDBLOCK || err == WSAEINTR) {
+                    continue;
+                }
+                reply.error = HTTP_READ_ERROR;
+                return reply;
+            }
+
+            if (nrecv == 0) {
+                reply.error = HTTP_EOF;
+                return reply;
+            }
+
+            chunk_buffer.insert(chunk_buffer.end(), recv_buf, recv_buf + nrecv);
+
+            // Sanity check
+            if (body.size() + chunk_buffer.size() > MAX_BODY_SIZE) {
+                throw std::runtime_error("HTTP response body too large");
+            }
+        }
+
+        reply.body = std::move(body);
+    } else if (content_length > 0) {
+        // Fixed content length
+        while (body_buffer.size() < content_length) {
+            if (std::chrono::steady_clock::now() >= deadline) {
+                reply.error = HTTP_TIMEOUT;
+                return reply;
+            }
+
+            auto time_left = std::chrono::duration_cast<std::chrono::milliseconds>(
+                deadline - std::chrono::steady_clock::now());
+            if (time_left.count() <= 0 || !WaitForReadable(sock, time_left)) {
+                reply.error = HTTP_TIMEOUT;
+                return reply;
+            }
+
+            std::byte recv_buf[4096];
+            ssize_t nrecv = sock.Recv(recv_buf, sizeof(recv_buf), /*flags=*/0);
+
+            if (nrecv < 0) {
+                int err = WSAGetLastError();
+                if (err == WSAEWOULDBLOCK || err == WSAEINTR) {
+                    continue;
+                }
+                reply.error = HTTP_READ_ERROR;
+                return reply;
+            }
+
+            if (nrecv == 0) {
+                reply.error = HTTP_EOF;
+                return reply;
+            }
+
+            body_buffer.insert(body_buffer.end(), recv_buf, recv_buf + nrecv);
+        }
+
+        reply.body = std::string(reinterpret_cast<const char*>(body_buffer.data()), content_length);
+    } else {
+        // No body or read until connection close
+        reply.body = std::string(reinterpret_cast<const char*>(body_buffer.data()), body_buffer.size());
+    }
+
+    reply.error = HTTP_NO_ERROR;
+    return reply;
+}
+
+HTTPReply HTTPClient::Post(const std::string& endpoint,

